  '<h3 id="http-client-cookie-jar">b.httpClient.cookieJar.create(opts?) <a class="anchor" href="#http-client-cookie-jar">#</a></h3>',
  '<pre><code class="language-javascript">{',
  '  persist:        "memory" | "vault" | "file",  // default: "memory"',
  '  vault:          vaultInstance,            // required when persist === "vault"',
