  'try { b.safeUrl.parse("file:///etc/passwd"); }',
  'catch (e) { /* SafeUrlError code: PROTOCOL_NOT_ALLOWED */ }</code></pre>',

  '<h2 id="allowed-hosts">Outbound destination allowlist</h2>',

  '<h3>b.httpClient.request({ allowedHosts }) <a class="anchor" href="#allowed-hosts-call">#</a></h3>',
  '<pre><code class="language-javascript">{',
  '  allowedHosts: [',
  '    string,                                  // exact match: "api.partner.com"',
  '    string,                                  // suffix match: ".internal.example.com"',
